// Generated by GitHub Copilot
const mysql = require("mysql2");

/**
 * Use a connection pool for production reliability.
 * A pool automatically handles dropped connections and concurrent queries,
 * which is essential when hosted on Render (connections may idle-timeout).
 */
const pool = mysql.createPool({
   host: process.env.MYSQLHOST,
   user: process.env.MYSQLUSER,
   password: process.env.MYSQLPASSWORD,
   database: process.env.MYSQLDATABASE,
   port: process.env.MYSQLPORT || 3306,
   waitForConnections: true,
   connectionLimit: 10,
   queueLimit: 0,
   ssl: {
      rejectUnauthorized: false
   }
});

// Verify the pool can reach the database on startup
pool.getConnection((err, connection) => {
   if (err) {
      console.log("DATABASE CONNECTION ERROR:", err.message);
   } else {
      console.log("MySQL Pool Connected");
      connection.release();
   }
});

module.exports = pool;